var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"저쪽이다! 저쪽으로 도망쳤어!","JPN":"あっちだ！　あっちに逃げたぞ！","ENG":"There! They went that way!","TWN":"在那邊！逃到那邊去了！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"겨우 두 명으로 우리 기지에 숨어들려고 했겠다?!","JPN":"たった二人で、基地に侵入しようとしたのか！？","ENG":"Did they really think they could sneak in with just the two of them?","TWN":"就兩個人也想混進我們的基地裡？!"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"우습게 보지 말라고!","JPN":"甘く見られたもんだな！","ENG":"They'll be sorry!","TWN":"少瞧不起人了！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"시간 끌지 마! 건물째 쓸어 버려!","JPN":"これ以上時間をやる必要はない！　建物ごと一掃しろ！","ENG":"Don't waste any more time! Just wipe out the whole building!","TWN":"不要浪費時間！把整個建築物給轟了！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......적 병력이 너무 많군요. 이래서야 따돌리고 다시 침투하기는 어렵겠습니다.","JPN":"……敵の兵力が多すぎます。これでは敵をまいて、再侵入するのは難しいかと。","ENG":"There are too many hostiles. It will be difficult to lose them and try to infiltrate again.","TWN":"……敵人兵力太多了，很難把他們甩掉重新混進去。"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"차라리 그때 잡혀 가는 게 나았겠다!","JPN":"いっそ、あの時捕まってた方が良かったわ！","ENG":"I should've just opted for prison!","TWN":"還不如那時直接被他們抓走！"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이런 야만스런 작전에 날 집어넣다니 대체 무슨 생각인 거야, 그 아줌마!","JPN":"あのおばさんったら！　こんな野蛮な作戦にアタシを投入するとか、一体何を考えてるわけ？","ENG":"What's that crazy thinking, inserting me into a brutish operation like this, Maria?!","TWN":"居然讓我參與這種野蠻的作戰，那個大嬸在想什麼啊！"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"돌아가면 가만 안 둘 줄 알아!","JPN":"戻ったら、覚えておきなさいよ！","ENG":"That crazy old hag will be sorry if I ever make it back!","TWN":"回去後我絕對不會輕易放過她的！"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"쿠퍼 씨, 사령관님께 무슨 망발입니까! 언동에 주의해 주십시오!","JPN":"クーパーさん、司令官に向かって暴言を吐くとは何ごとですか！　言動には十分注意してください！","ENG":"Ms. Cooper! That's no way to talk about the Commander! Please watch your language!","TWN":"庫博小姐，妳這是對司令官說話的語氣嗎！請注意妳的用詞！"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내 언동 신경 쓸 시간에 쟤들 총 쏘는 거나 어떻게 해 보라고!","JPN":"アタシの言動を気にしている暇があったら、あいつらの銃を何とかしなさいよ！","ENG":"Why don't you watch their guns if you've got time to watch my language?!","TWN":"有時間要我注意用詞，還不如開槍做點什麼！"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"흠......","JPN":"ふむ……","ENG":"Hmm...","TWN":"哼……"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"견착 자세가 엉망이군요.","JPN":"銃を撃つ姿勢がなっていませんね。","ENG":"Their firing postures are all wrong.","TWN":"肩膀姿勢太差了。"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"엄폐물을 향해 무작정 쏘기만 하는 걸 보니 상대는 전술적 행동에 대한 교육을 받은 적이 전혀 없는 것 같습니다.","JPN":"遮蔽物にむやみやたらと銃弾を撃ち込んでいるところを見ると、相手は戦術的行動に関する教育を受けたことがないようですね。","ENG":"And they just keep shooting blindly from behind cover. It appears they have never received any tactical training.","TWN":"對方只會對掩蔽物盲目地進行射擊，看來他們應該沒有接受過正式的戰術訓練。"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"누가 너더러 점수 매기라고 했어?! 그 눈먼 총알에 우리 둘 다 죽게 생겼잖아!","JPN":"誰が今、アンタにあいつらを評価しろって言ったわけ？　その銃弾で今、アタシたち死にそうなんだけど！？","ENG":"I didn't ask you to rate them! Those blindfire bullets are about to kill us both!","TWN":"誰要你給他們評分了？！那些亂打的子彈會要了我們的命好嘛！"},"stage":{"bg":"WARZONE_03","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"적들이 가득한 지역에 달랑 둘만 보내 놓고 기밀 자료를 빼 오라고 해?","JPN":"こんなに敵がいっぱいいる場所にアタシたち二人だけ投入しておいて、機密資料を奪って来いなんてどうかしてるでしょ！","ENG":"This place is crawling with them! And we're suppose to steal their classified data with just the two of us?","TWN":"只派兩個人去擠滿敵人的基地奪取機密資料？"},"stage":{"bg":"WARZONE_03","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"대체 어떤 돌머리가 내놓은 작전이야?","JPN":"どんな石頭がこんな作戦を立てたわけ？","ENG":"Which genius came up with this plan?","TWN":"到底是哪個天才想到的計畫？"},"stage":{"bg":"WARZONE_03","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};